INSERT INTO text_snippets (type, content) VALUES
('joke', 'Proč si kohout v jednom kuse spokojeně kokrhá?\nMá spoustu žen a žádnou tchýni.'),
('joke', 'Slyšeli jste o tom nesnesitelném kuřeti?\nJistěže ne - slepice ho přeci nemohla snést!'),
('joke', '„Celý měsíc jsem seděla na vejcích," stěžuje si slepice, „a pak jsem zjistila, že jsou vařená!"\nKohout vletí do kuchyně a tam vidí svého kolegu pečeného na víně a zaběduje: „Já to tušil, že alkohol zabíjí!"'),
('joke', 'Nadává kohout pštrosovi: „Ty lumpe, co má znamenat to obří vejce v mém kurníku?! Za to ti rozbiju čenich!"\n„Ale nerozbiješ," pousměje se pštros, „já mám totiž jen zobák."'),
('joke', 'Proč se má slepice nejlíp?\nProtože je zazobaná a ještě si nahrabe.'),
('joke', 'Ze které strany má slepice víc peří?\nZ té vnější.'),
('joke', 'Povídá slepice kuřatům: „Kdyby váš táta viděl, jak pořád zlobíte, tak by se na grilu obracel!"'),
('joke', 'Kuře se prochází po kurníku s cigaretou v zobáku. Přijde k němu kohout: „Okamžitě to vyhoď, nebo to řeknu tvé mámě!"\n„Říkej si to, komu chceš," ušklíbne se kuře, „já jsem z umělé líhně."'),
('joke', '„Proč včera večer váš kohout tak strašně řval?"\n„Ale, přetáčel jsem ho na zimní čas."'),
('joke', 'Starý kohout honí po dvoře slepici.\n„Co blázníš," volá na něho kozel, „stejně ji nedohoníš."\n„To vím, ale aspoň se zahřeju."'),
('joke', 'Jak poznáte moderní slepici?\nSnáší Kinder vajíčka.'),
('joke', '„Tati, prdí slépky?"\n„Ale co tě vede, synku, to je babička v kurníku!"'),
('joke', 'Víte, proč kohout kokrhá tak brzy ráno?\nProtože když vstanou slepice, tak už nemá šanci.'),
('joke', 'Povídají si dvě slepice: „Jó, holka, to já měla nedávno takovou horečku, že jsem snášela vejce na tvrdo."'),
('joke', 'Kohout přikutálel na dvůr pštrosí vejce a říká: „Ne že bych vás chtěl nějak prudit, ale podívejte se, co umí v cizině..."'),
('joke', 'Tři slepice si hrají na schovávanou. Jedna piká a dvě se schovávají. První se schová do šopy a druhá do kurníku. Třetí počítá: „8, 9, 10... už jdu!"\nJde a zakopne o klacek položený na zemi.\n„Kurník šopa!"\nSchované slepice vylezou a volají: „To neplatí, ty ses dívala."'),
('joke', 'Slepice: „Nebudeš-li hodné, sežere tě tchoř!"\nKuře: „A budu-li hodné, maminko?"\nSlepice: „Pak tě sní jenom lidé."'),
('joke', 'Přijde kohout do porodnice a sestřička povídá: „Blahopřeji, je to vejce."'),
('joke', 'Víte, kdy kuře naposledy pípne?\nV supermarketu na pokladně.'),
('joke', 'Víte, jaký je rozdíl mezi slepicí a dálnicí?\nNa slepici může jezdit jenom kohout, kdežto na dálnici každý vůl!'),
('joke', 'Bavili se dva kohouti.\n„Představ si, že ta moje slepice snesla včera hranatý vejce."\n„A co říkala?"\n„Au."'),
('joke', 'Víš, co napadne kohouta, když jeho slepice snese sedmikilové vejce?\nŽe asi pštrosovi rozbije hubu!'),
('joke', 'Jaký je oblíbený hudební žánr kuřat?\nHip-hop!'),
('joke', 'Proč vejce nikdy nevyhrávají hádky?\nProtože se vždycky rozklepou!'),
('joke', 'Jak se kuřata zdraví?\n„Čau, kámo! Jak se peří?"');
